using System.Collections;
using UnityEngine;

/// <summary>
/// "Pausa NPCs em movimento" (Etapa 8): suspende temporariamente o
/// NpcMovement de qualquer NPC que esteja actualmente em
/// FollowPlayer/FleePlayer/Patrol (tratados como "inimigos"/NPCs em movimento
/// autónomo perto do player), restaurando o respectivo "DefaultMode" quando
/// Action_ResumeNearbyNpcs for executada. NPCs em Idle, ou a meio de uma ação
/// de cutscene própria (ex: MoveToTarget), não são afectados.
/// </summary>
[System.Serializable]
public class Action_PauseNearbyNpcs : NpcAction
{
    [Tooltip("Raio (a partir do player deste NPC) dentro do qual outros NPCs em FollowPlayer/FleePlayer/Patrol são pausados. 0 ou menos = sem limite (todos os NPCs da cena).")]
    public float radius = 15f;

    public override IEnumerator Execute(NpcController npc)
    {
        NpcPauseUtil.PauseNearbyNpcs(npc, radius);
        yield break;
    }
}

/// <summary>Retoma o movimento de todos os NPCs pausados pela última Action_PauseNearbyNpcs.</summary>
[System.Serializable]
public class Action_ResumeNearbyNpcs : NpcAction
{
    public override IEnumerator Execute(NpcController npc)
    {
        NpcPauseUtil.ResumePausedNpcs();
        yield break;
    }
}

/// <summary>
/// "Pausa física" do jogo (Etapa 8): Time.timeScale = 0, parando toda a física,
/// animações e Update/FixedUpdate escalados por timeScale (incluindo o
/// movimento de outros NPCs e do player). A sequência de ações deste evento
/// continua a correr — Action_Wait (e outras ações com tempos de espera) usam
/// automaticamente WaitForSecondsRealtime enquanto Time.timeScale == 0 (ver
/// NpcActionUtil.Wait), por isso podes encadear, por exemplo, "Pausar Jogo" →
/// "Esperar 2s" → "Retomar Jogo" para um pequeno "freeze" controlado.
/// Ações que dependam de FixedUpdate (ex: movimento de NPC por física) não
/// avançam enquanto o jogo estiver pausado desta forma.
/// </summary>
[System.Serializable]
public class Action_PauseGame : NpcAction
{
    public override IEnumerator Execute(NpcController npc)
    {
        GamePauseUtil.Pause();
        yield break;
    }
}

/// <summary>Desfaz Action_PauseGame, restaurando o Time.timeScale anterior.</summary>
[System.Serializable]
public class Action_ResumeGame : NpcAction
{
    public override IEnumerator Execute(NpcController npc)
    {
        GamePauseUtil.Resume();
        yield break;
    }
}
